  "learningCards": [
    {
      "title": "Kegunaan Bahan Pembinaan",
      "content": "Bahan pembinaan adalah elemen asas dalam setiap projek pembinaan. Terdapat pelbagai jenis bahan, termasuk kayu, batu, konkrit, dan logam. Memahami kegunaan setiap bahan adalah penting untuk membuat pilihan yang tepat dalam projek pembinaan.",
      "layout": "standard"
    },
    {
      "title": "Kelebihan dan Kekurangan",
      "content": "Setiap bahan pembinaan mempunyai kelebihan dan kekurangan tersendiri. Contohnya, kayu adalah ringan dan mudah dibentuk, tetapi mungkin terdedah kepada serangan serangga. Sebaliknya, konkrit adalah kuat dan tahan lama, tetapi berat dan memerlukan masa untuk mengering.",
      "layout": "standard"
    },
    {
      "title": "Pemilihan Bahan yang Tepat",
      "content": "Memilih bahan yang sesuai untuk projek pembinaan bergantung kepada faktor seperti kos, ketersediaan, dan keperluan spesifik projek. Rujuk kepada 'Pengenalan kepada Bahan Pembinaan' untuk mendapatkan petunjuk dalam membuat pilihan yang tepat.",
      "layout": "standard"
    },
    {
      "title": "Kegunaan Spesifik",
      "content": "Kayu sering digunakan untuk rangka dan struktur, batu untuk dinding dan asas, konkrit untuk lantai dan dinding, dan logam untuk kekuatan tambahan. Memahami kegunaan spesifik ini membantu dalam merancang projek dengan lebih baik.",
      "layout": "standard"
    }
  ]
}
